1695	    autoparser::generation_params params;
1696	    params.tools = common_chat_tools_to_json_oaicompat(inputs.tools);
1697	    const auto & tmpl =
1698	        params.tools.is_array() && tmpls->template_tool_use ? *tmpls->template_tool_use : *tmpls->template_default;
1699	    const auto & src        = tmpl.source();
1700	    const auto & caps       = tmpl.original_caps();
1701	    params.messages         = render_message_to_json(inputs.messages, tmpl.original_caps());
1702	    params.tool_choice      = inputs.tool_choice;
1703	    params.reasoning_format = inputs.reasoning_format;
1704	    params.enable_thinking  = inputs.enable_thinking;
1705	    params.grammar          = inputs.grammar;
1706	    params.now              = inputs.now;
1707	    params.add_bos          = tmpls->add_bos;
1708	    params.add_eos          = tmpls->add_eos;
1709	
1710	    if (src.find("<|channel|>") == std::string::npos) {
1711	        // map developer to system for all models except for GPT-OSS
1712	        workaround::map_developer_role_to_system(params.messages);
1713	    }
1714	
1715	    if (!tmpl.original_caps().supports_system_role) {
1716	        workaround::system_message_not_supported(params.messages);
1717	    }
1718	
1719	    if (tmpl.original_caps().supports_tool_calls) {
1720	        // some templates will require the content field in tool call messages
1721	        // to still be non-null, this puts an empty string everywhere where the
1722	        // content field is null
1723	        workaround::requires_non_null_content(params.messages);
1724	    }
1725	
1726	    if (tmpl.original_caps().supports_object_arguments) {
1727	        workaround::func_args_not_string(params.messages);
1728	    }
1729	
1730	    if (src.find("'<|tool_call>call:'") != std::string::npos) {
1731	        workaround::convert_tool_responses_gemma4(params.messages);
1732	    }
1733	
1734	    params.add_generation_prompt = false;
1735	    std::string no_gen_prompt    = common_chat_template_direct_apply_impl(tmpl, params);
1736	    params.add_generation_prompt = true;
1737	    std::string gen_prompt       = common_chat_template_direct_apply_impl(tmpl, params);
1738	    auto        diff             = calculate_diff_split(no_gen_prompt, gen_prompt);
1739	    params.generation_prompt     = diff.right;
1740	
1741	    params.add_generation_prompt = inputs.add_generation_prompt;
1742	
1743	    params.extra_context = common_chat_extra_context();
1744	    for (auto el : inputs.chat_template_kwargs) {
1745	        params.extra_context[el.first] = json::parse(el.second);
1746	    }
1747	
1748	    if (!inputs.json_schema.empty()) {
1749	        params.json_schema = json::parse(inputs.json_schema);
1750	    }
1751	
1752	    params.parallel_tool_calls = inputs.parallel_tool_calls;
1753	
1754	    if (params.tools.is_array()) {
1755	        if (params.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE && !params.grammar.empty()) {
1756	            throw std::runtime_error("Cannot specify grammar with tools");
1757	        }
1758	        if (caps.supports_tool_calls && !caps.supports_tools) {
1759	            LOG_WRN(
1760	                "Template supports tool calls but does not natively describe tools. The fallback behaviour used may "
1761	                "produce bad results, inspect prompt w/ --verbose & consider overriding the template.\n");
1762	        }
1763	    }
1764	
1765	    if (inputs.force_pure_content) {
1766	        LOG_WRN("Forcing pure content template, will not render reasoning or tools separately.");
1767	        // Create the result structure
1768	        common_chat_params data;
1769	        auto params_copy               = params;
1770	        params_copy.reasoning_format   = COMMON_REASONING_FORMAT_NONE;
1771	        data.prompt                    = common_chat_template_direct_apply_impl(tmpl, params_copy);
1772	        data.format                    = COMMON_CHAT_FORMAT_PEG_NATIVE;
1773	        data.generation_prompt         = params.generation_prompt;
1774	        auto parser                    = build_chat_peg_parser([&params](common_chat_peg_builder &p) {
1775	            return p.prefix(params.generation_prompt) << p.content(p.rest());
1776	        });
1777	        data.parser                    = parser.save();
1778	        return data;
1779	    }
1780	
1781	    if (auto result = common_chat_try_specialized_template(tmpl, src, params)) {
1782	        result->generation_prompt = params.generation_prompt;
1783	        return *result;

825	static common_chat_params common_chat_params_init_ministral_3(const common_chat_template &    tmpl,
826	                                                              const autoparser::generation_params & inputs) {
827	    common_chat_params data;
828	
829	    // Build up messages to follow the format: https://huggingface.co/mistralai/Ministral-3-14B-Reasoning-2512/blob/main/chat_template.jinja
830	    auto adjusted_messages = json::array();
831	    for (const auto & msg : inputs.messages) {
832	        auto role = msg.value("role", "");
833	        if (role != "system" && role != "assistant") {
834	            // Only adjust system and assistant messages. Interestingly, the system message may contain thinking.
835	            adjusted_messages.push_back(msg);
836	            continue;
837	        }
838	
839	        auto content = json::array();
840	
841	        // If message contains `reasoning_content`, add it as a block of type `thinking`
842	        if (msg.contains("reasoning_content") && msg.at("reasoning_content").is_string()) {
843	            content.push_back({
844	                { "type",     "thinking"                                     },
845	                { "thinking", msg.at("reasoning_content").get<std::string>() },
846	            });
847	        }
848	
849	        // If message contains `content`, add it as a block of type `text`
850	        if (msg.contains("content")) {
851	            if (msg.at("content").is_string()) {
852	                content.push_back({
853	                    { "type", "text"                               },
854	                    { "text", msg.at("content").get<std::string>() },
855	                });
856	            } else if (msg.at("content").is_array()) {
857	                auto blocks = msg.at("content");
858	                content.insert(content.end(), blocks.begin(), blocks.end());
859	            }
860	        }
861	
862	        auto adjusted       = msg;
