static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    std::string prompt = "<s>";
    std::string system_message;

    // First pass: extract system message if present
    for (const auto & msg : inputs.messages) {
        auto role = msg.value("role", "");
        if (role == "system") {
            system_message = msg.value("content", "");
            break;
        }
    }

    bool first_user = true;
    for (const auto & msg : inputs.messages) {
        auto role    = msg.value("role", "");
        auto content = msg.value("content", "");

        if (role == "system") {
            // System message handled by prepending to first user turn
            continue;
        } else if (role == "user") {
            if (first_user && !system_message.empty()) {
                prompt += "[INST] " + system_message + "\n" + content + " [/INST]";
            } else {
                prompt += "[INST] " + content + " [/INST]";
            }
            first_user = false;
        } else if (role == "assistant") {
            prompt += content + "</s>";
        }
    }

    data.prompt = prompt;
    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;

    return data;
}

